"use strict";(globalThis.webpackChunkself_healing_nixos_infra=globalThis.webpackChunkself_healing_nixos_infra||[]).push([[239],{8404(e){e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"\u5f53\u524d\u7248\u672c","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"tutorialSidebar":[{"type":"link","href":"/self-healing-nixos-infra/zh/","label":"\u7b80\u4ecb","docId":"intro","unlisted":false},{"type":"link","href":"/self-healing-nixos-infra/zh/architecture","label":"\u67b6\u6784\u6982\u89c8","docId":"architecture","unlisted":false},{"type":"category","label":"\u5f15\u5bfc\u4e0e\u6587\u4ef6\u7cfb\u7edf","items":[{"type":"link","href":"/self-healing-nixos-infra/zh/bootstrap-nixos-anywhere","label":"Bootstrap with nixos-anywhere","docId":"bootstrap-nixos-anywhere","unlisted":false},{"type":"link","href":"/self-healing-nixos-infra/zh/btrfs-layout","label":"Btrfs Subvolume Layout","docId":"btrfs-layout","unlisted":false},{"type":"link","href":"/self-healing-nixos-infra/zh/btrfs-snapshots","label":"Btrfs Snapshots & Snapper","docId":"btrfs-snapshots","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"AI \u57fa\u7840\u8bbe\u65bd\u7ba1\u7406","items":[{"type":"link","href":"/self-healing-nixos-infra/zh/install-openclaw","label":"Install OpenClaw","docId":"install-openclaw","unlisted":false},{"type":"link","href":"/self-healing-nixos-infra/zh/ai-managed-infra","label":"AI-Managed Infrastructure","docId":"ai-managed-infra","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"\u5b89\u5168\u4e0e\u6062\u590d","items":[{"type":"link","href":"/self-healing-nixos-infra/zh/totp-sudo-protection","label":"TOTP Sudo Protection","docId":"totp-sudo-protection","unlisted":false},{"type":"link","href":"/self-healing-nixos-infra/zh/database-snapshot-strategy","label":"Database Snapshot Strategy","docId":"database-snapshot-strategy","unlisted":false},{"type":"link","href":"/self-healing-nixos-infra/zh/disaster-recovery","label":"Disaster Recovery","docId":"disaster-recovery","unlisted":false},{"type":"link","href":"/self-healing-nixos-infra/zh/ai-safety-and-rollback","label":"AI Safety & Rollback","docId":"ai-safety-and-rollback","unlisted":false}],"collapsed":true,"collapsible":true}]},"docs":{"ai-managed-infra":{"id":"ai-managed-infra","title":"AI-Managed Infrastructure","description":"With OpenClaw installed, this chapter defines the operational model: what the AI manages autonomously, what requires human approval, and how the entire change pipeline works.","sidebar":"tutorialSidebar"},"ai-safety-and-rollback":{"id":"ai-safety-and-rollback","title":"AI Safety & Rollback","description":"This final chapter defines the operating procedures for running AI-managed infrastructure safely. It covers guardrails, rollback workflows, failure budgets, and the principles that keep humans in control while benefiting from AI automation.","sidebar":"tutorialSidebar"},"architecture":{"id":"architecture","title":"\u67b6\u6784\u6982\u89c8","description":"\u672c\u6587\u6863\u63cf\u8ff0\u5b8c\u6574\u7684\u7cfb\u7edf\u67b6\u6784\u3001\u7ec4\u4ef6\u4ea4\u4e92\u3001\u6570\u636e\u6d41\u548c\u6545\u969c\u5904\u7406\u7b56\u7565\u3002","sidebar":"tutorialSidebar"},"bootstrap-nixos-anywhere":{"id":"bootstrap-nixos-anywhere","title":"Bootstrap with nixos-anywhere","description":"nixos-anywhere lets you install NixOS on any Linux server with root SSH access \u2014 no ISO image, no console access, no provider-specific tooling. It works by kexec-ing into a NixOS installer in RAM, partitioning the disk, and installing your declared configuration.","sidebar":"tutorialSidebar"},"btrfs-layout":{"id":"btrfs-layout","title":"Btrfs Subvolume Layout","description":"A well-designed subvolume layout is the foundation of a rollback-capable system. Each subvolume can be independently snapshotted, mounted with different options, and excluded from rollbacks when persistence is needed.","sidebar":"tutorialSidebar"},"btrfs-snapshots":{"id":"btrfs-snapshots","title":"Btrfs Snapshots & Snapper","description":"Snapshots are the core of the rollback strategy. This chapter covers manual snapshots, automated management with Snapper, and pre-rebuild hooks that ensure every system change has a restore point.","sidebar":"tutorialSidebar"},"database-snapshot-strategy":{"id":"database-snapshot-strategy","title":"Database Snapshot Strategy","description":"Databases require special snapshot handling. A naive filesystem snapshot of a running database can capture an inconsistent state \u2014 half-written transactions, dirty buffers, incomplete WAL entries. This chapter covers strategies for consistent database snapshots on Btrfs.","sidebar":"tutorialSidebar"},"disaster-recovery":{"id":"disaster-recovery","title":"Disaster Recovery","description":"This chapter is the runbook. It covers every major failure scenario, the detection method, and step-by-step recovery procedures. Print this page and keep it accessible \u2014 you\'ll need it when things go wrong.","sidebar":"tutorialSidebar"},"faq":{"id":"faq","title":"FAQ","description":"Btrfs & Snapshots"},"install-openclaw":{"id":"install-openclaw","title":"Install OpenClaw","description":"OpenClaw is an AI-powered infrastructure operator. It monitors system health, proposes configuration changes, and can execute approved operations \u2014 all within a policy-defined boundary. Think of it as an AI SRE agent that works alongside your existing NixOS tooling.","sidebar":"tutorialSidebar"},"intro":{"id":"intro","title":"\u7b80\u4ecb","description":"\u672c\u6559\u7a0b\u5c06\u6307\u5bfc\u60a8\u6784\u5efa\u4e00\u4e2a\u751f\u4ea7\u7ea7\u81ea\u6108\u670d\u52a1\u5668\uff0c\u5b83\u7ed3\u5408\u4e86\u58f0\u660e\u5f0f\u7cfb\u7edf\u7ba1\u7406\u3001\u5199\u65f6\u590d\u5236\u5feb\u7167\u3001AI \u8f85\u52a9\u64cd\u4f5c\u548c TOTP \u4fdd\u62a4\u7684\u4e34\u754c\u64cd\u4f5c\u3002","sidebar":"tutorialSidebar"},"totp-sudo-protection":{"id":"totp-sudo-protection","title":"TOTP Sudo Protection","description":"This chapter configures TOTP (Time-based One-Time Password) authentication for sudo, ensuring that critical operations like nixos-rebuild switch require a 6-digit code from an authenticator app \u2014 even if an attacker gains shell access.","sidebar":"tutorialSidebar"}}}}')}}]);